
//
// SmoothScroll (Balazs Galambosi) — standalone embeddable version
// Licensed under the terms of the MIT license.
//

// Scroll Variables (tweakable)
var defaultOptions = {

    // Scrolling Core
    frameRate        : 150, // [Hz]
    animationTime    : 400, // [px]
    stepSize         : 100, // [px]

    // Pulse (less tweakable)
    pulseAlgorithm   : true,
    pulseScale       : 4,
    pulseNormalize   : 1,

    // Acceleration
    accelerationDelta : 50,
    accelerationMax   : 3,

    // Keyboard Settings
    keyboardSupport   : true,
    arrowScroll       : 50,

    // Other
    touchpadSupport   : false,
    fixedBackground   : true,
    excluded          : ''
};

var options = defaultOptions;


// Other Variables
var isExcluded = false;
var isFrame = false;
var direction = { x: 0, y: 0 };
var initDone  = false;
var root = document.documentElement;
var activeElement;
var observer;
var deltaBuffer = [];
var deltaBufferTimer;
var isMac = /^Mac/.test(navigator.platform);
var isWin = /Windows/i.test(navigator.userAgent);

var key = { left: 37, up: 38, right: 39, down: 40, spacebar: 32,
            pageup: 33, pagedown: 34, end: 35, home: 36 };
var arrowKeys = { 37: 1, 38: 1, 39: 1, 40: 1 };


/***********************************************
 * INITIALIZE
 ***********************************************/

function initTest() {
    if (!options.keyboardSupport) {
        removeEvent('keydown', keydown);
    }
    if (options.excluded) {
        var domains = options.excluded.split(/[,\n] ?/);
        for (var i = domains.length; i--;) {
            if (document.URL.indexOf(domains[i]) > -1) {
                isExcluded = true;
                cleanup();
                return;
            }
        }
    }
}

function init() {
    if (initDone || isExcluded || !document.body) {
        return;
    }
    initDone = true;

    var body = document.body;
    var html = document.documentElement;
    var windowHeight = window.innerHeight;
    var scrollHeight = body.scrollHeight;

    root = (document.compatMode.indexOf('CSS') >= 0) ? html : body;
    activeElement = body;

    if (top != self) {
        isFrame = true;
    } else if (scrollHeight > windowHeight &&
               (body.clientHeight + 1 < body.scrollHeight &&
                html.clientHeight + 1 < html.scrollHeight)) {
        if (root.offsetHeight <= windowHeight) {
            var clearfix = document.createElement('div');
            clearfix.style.clear = 'both';
            body.appendChild(clearfix);
        }
    }

    if (!options.fixedBackground && !isExcluded) {
        body.style.backgroundAttachment = 'scroll';
        html.style.backgroundAttachment = 'scroll';
    }

    if (!isFrame) {
        addEvent('message', function (e) {
            if (e.data.SS == 'SmoothScroll') {
                var wheelEvent = e.data;
                wheelEvent.target = getFrameByEvent(e);
                wheel(wheelEvent);
            }
        });
    }
}

function getFrameByEvent(event) {
    var iframes = document.getElementsByTagName('iframe');
    return [].filter.call(iframes, function(iframe) {
        return iframe.contentWindow === event.source;
    })[0];
}

function cleanup() {
    observer && observer.disconnect();
    removeEvent(wheelEvent, wheel);
    removeEvent('mousedown', mousedown);
    removeEvent('keydown', keydown);
}

function loaded() {
    setTimeout(function () {
        init();
        if (options.keyboardSupport) {
            removeEvent('keydown', keydown);
            addEvent('keydown', keydown);
        }
    }, 1);
}


/************************************************
 * SCROLLING
 ************************************************/

var que = [];
var pending = null;
var lastScroll = Date.now();

function scrollArray(elem, left, top) {
    directionCheck(left, top);

    if (options.accelerationMax != 1) {
        var now = Date.now();
        var elapsed = now - lastScroll;
        if (elapsed < options.accelerationDelta) {
            var factor = (1 + (50 / elapsed)) / 2;
            if (factor > 1) {
                factor = Math.min(factor, options.accelerationMax);
                left *= factor;
                top  *= factor;
            }
        }
        lastScroll = Date.now();
    }

    que.push({
        x: left,
        y: top,
        lastX: (left < 0) ? 0.99 : -0.99,
        lastY: (top  < 0) ? 0.99 : -0.99,
        start: Date.now()
    });

    if (pending) {
        return;
    }

    var scrollRoot = getScrollRoot();
    var isWindowScroll = (elem === scrollRoot || elem === document.body);

    if (elem.$scrollBehavior == null && isScrollBehaviorSmooth(elem)) {
        elem.$scrollBehavior = elem.style.scrollBehavior;
        elem.style.scrollBehavior = 'auto';
    }

    var step = function (time) {

        var now = Date.now();
        var scrollX = 0;
        var scrollY = 0;

        for (var i = 0; i < que.length; i++) {
            var item = que[i];
            var elapsed  = now - item.start;
            var finished = (elapsed >= options.animationTime);
            var position = (finished) ? 1 : elapsed / options.animationTime;

            if (options.pulseAlgorithm) {
                position = pulse(position);
            }

            var x = (item.x * position - item.lastX) >> 0;
            var y = (item.y * position - item.lastY) >> 0;

            scrollX += x;
            scrollY += y;

            item.lastX += x;
            item.lastY += y;

            if (finished) {
                que.splice(i, 1); i--;
            }
        }

        if (isWindowScroll) {
            window.scrollBy(scrollX, scrollY);
        } else {
            if (scrollX) elem.scrollLeft += scrollX;
            if (scrollY) elem.scrollTop  += scrollY;
        }

        if (!left && !top) {
            que = [];
        }

        if (que.length) {
            pending = window.requestAnimationFrame(step);
        } else {
            pending = null;
            if (elem.$scrollBehavior != null) {
                elem.style.scrollBehavior = elem.$scrollBehavior;
                elem.$scrollBehavior = null;
            }
        }
    };

    pending = window.requestAnimationFrame(step);
}


/***********************************************
 * EVENTS
 ***********************************************/

function wheel(event) {
    if (!initDone) {
        init();
    }

    var target = event.target;

    if (event.defaultPrevented || event.ctrlKey) {
        return true;
    }

    if (isNodeName(activeElement, 'embed') ||
       (isNodeName(target, 'embed') && /\.pdf/i.test(target.src)) ||
        isNodeName(activeElement, 'object') ||
        target.shadowRoot) {
        return true;
    }

    var deltaX = -event.wheelDeltaX || event.deltaX || 0;
    var deltaY = -event.wheelDeltaY || event.deltaY || 0;

    if (isMac) {
        if (event.wheelDeltaX && isDivisible(event.wheelDeltaX, 120)) {
            deltaX = -120 * (event.wheelDeltaX / Math.abs(event.wheelDeltaX));
        }
        if (event.wheelDeltaY && isDivisible(event.wheelDeltaY, 120)) {
            deltaY = -120 * (event.wheelDeltaY / Math.abs(event.wheelDeltaY));
        }
    }

    if (!deltaX && !deltaY) {
        deltaY = -event.wheelDelta || 0;
    }

    if (event.deltaMode === 1) {
        deltaX *= 40;
        deltaY *= 40;
    }

    if (!options.touchpadSupport && isTouchpad(deltaY)) {
        return true;
    }

    var xOnly = (deltaX && !deltaY);
    var overflowing = overflowingAncestor(target, xOnly);

    if (!overflowing) {
        if (isFrame) {
            event.preventDefault();
            postScrollToParent(deltaX, deltaY);
        }
        return true;
    }

    if (Math.abs(deltaX) > 1.2) {
        deltaX *= options.stepSize / 120;
    }
    if (Math.abs(deltaY) > 1.2) {
        deltaY *= options.stepSize / 120;
    }

    scrollArray(overflowing, deltaX, deltaY);
    if (event.preventDefault) event.preventDefault();
    scheduleClearCache();
}

function keydown(event) {
    var target   = event.target;
    var modifier = event.ctrlKey || event.altKey || event.metaKey ||
                  (event.shiftKey && event.keyCode !== key.spacebar);

    if (!document.contains(activeElement)) {
        activeElement = document.activeElement;
    }

    var inputNodeNames = /^(textarea|select|embed|object)$/i;
    var buttonTypes = /^(button|submit|radio|checkbox|file|color|image)$/i;
    if ( event.defaultPrevented ||
         inputNodeNames.test(target.nodeName) ||
         isNodeName(target, 'input') && !buttonTypes.test(target.type) ||
         isNodeName(activeElement, 'video') ||
         isInsideYoutubeVideo(event) ||
         target.isContentEditable ||
         modifier ) {
      return true;
    }

    if ((isNodeName(target, 'button') ||
         isNodeName(target, 'input') && buttonTypes.test(target.type)) &&
        event.keyCode === key.spacebar) {
      return true;
    }

    if (isNodeName(target, 'input') && target.type == 'radio' &&
        arrowKeys[event.keyCode]) {
      return true;
    }

    var xOnly = (event.keyCode == key.left || event.keyCode == key.right);
    var overflowing = overflowingAncestor(activeElement, xOnly);

    if (!overflowing) {
        return isFrame ? parent.keydown(event) : true;
    }

    var clientHeight = overflowing.clientHeight;
    var shift, x = 0, y = 0;

    if (overflowing == document.body) {
        clientHeight = window.innerHeight;
    }

    switch (event.keyCode) {
        case key.up:
            y = -options.arrowScroll;
            break;
        case key.down:
            y = options.arrowScroll;
            break;
        case key.spacebar:
            shift = event.shiftKey ? 1 : -1;
            y = -shift * clientHeight * 0.9;
            break;
        case key.pageup:
            y = -clientHeight * 0.9;
            break;
        case key.pagedown:
            y = clientHeight * 0.9;
            break;
        case key.home:
            if (overflowing == document.body && document.scrollingElement)
                overflowing = document.scrollingElement;
            y = -overflowing.scrollTop;
            break;
        case key.end:
            var scroll = overflowing.scrollHeight - overflowing.scrollTop;
            var scrollRemaining = scroll - clientHeight;
            y = (scrollRemaining > 0) ? scrollRemaining+10 : 0;
            break;
        case key.left:
            x = -options.arrowScroll;
            break;
        case key.right:
            x = options.arrowScroll;
            break;
        default:
            return true;
    }

    scrollArray(overflowing, x, y);
    event.preventDefault();
    scheduleClearCache();
}

function mousedown(event) {
    activeElement = event.target;
}


/***********************************************
 * OVERFLOW
 ***********************************************/

var uniqueID = (function () {
    var i = 0;
    return function (el) {
        return el.uniqueID || (el.uniqueID = i++);
    };
})();

var cacheX = {};
var cacheY = {};
var clearCacheTimer;
var smoothBehaviorForElement = {};

function scheduleClearCache() {
    clearTimeout(clearCacheTimer);
    clearCacheTimer = setInterval(function () {
        cacheX = cacheY = smoothBehaviorForElement = {};
    }, 1*1000);
}

function setCache(elems, overflowing, x) {
    var cache = x ? cacheX : cacheY;
    for (var i = elems.length; i--;)
        cache[uniqueID(elems[i])] = overflowing;
    return overflowing;
}

function getCache(el, x) {
    return (x ? cacheX : cacheY)[uniqueID(el)];
}

function overflowingAncestor(el, x) {
    var elems = [];
    var body = document.body;
    var rootScrollHeight = root.scrollHeight;
    var rootScrollWidth  = root.scrollWidth;
    do {
        var cached = getCache(el, x);
        if (cached) {
            return setCache(elems, cached, x);
        }
        elems.push(el);
        if (x && rootScrollWidth  === el.scrollWidth ||
           !x && rootScrollHeight === el.scrollHeight) {
            var topOverflowsNotHidden = overflowNotHidden(root, x) && overflowNotHidden(body, x);
            var isOverflowCSS = topOverflowsNotHidden || overflowAutoOrScroll(root, x);
            if (isFrame && isContentOverflowing(root, x) ||
               !isFrame && isOverflowCSS) {
                return setCache(elems, getScrollRoot(), x);
            }
        } else if (isContentOverflowing(el, x) && overflowAutoOrScroll(el, x)) {
            return setCache(elems, el, x);
        }
    } while ((el = el.parentElement));
}

function isContentOverflowing(el, x) {
    return x ? (el.clientWidth  + 10 < el.scrollWidth)
             : (el.clientHeight + 10 < el.scrollHeight);
}

function computedOverflow(el, x) {
    var property = x ? 'overflow-x' : 'overflow-y';
    return getComputedStyle(el, '').getPropertyValue(property);
}

function overflowNotHidden(el, x) {
    return (computedOverflow(el, x) != 'hidden');
}

function overflowAutoOrScroll(el, x) {
    return /^(scroll|auto)$/.test(computedOverflow(el, x));
}

function isScrollBehaviorSmooth(el) {
    var id = uniqueID(el);
    if (smoothBehaviorForElement[id] == null) {
        var scrollBehavior = getComputedStyle(el, '')['scroll-behavior'];
        smoothBehaviorForElement[id] = ('smooth' == scrollBehavior);
    }
    return smoothBehaviorForElement[id];
}

function postScrollToParent(deltaX, deltaY) {
    parent.postMessage({
        deltaX: deltaX,
        deltaY: deltaY,
        SS: 'SmoothScroll'
    }, '*');
}


/***********************************************
 * HELPERS
 ***********************************************/

function addEvent(type, fn) {
    window.addEventListener(type, fn, false);
}

function removeEvent(type, fn) {
    window.removeEventListener(type, fn, false);
}

function isNodeName(el, tag) {
    return el && (el.nodeName||'').toLowerCase() === tag.toLowerCase();
}

function directionCheck(x, y) {
    x = (x > 0) ? 1 : -1;
    y = (y > 0) ? 1 : -1;
    if (direction.x !== x || direction.y !== y) {
        direction.x = x;
        direction.y = y;
        que = [];
        lastScroll = 0;
        window.cancelAnimationFrame(pending);
        pending = null;
    }
}

function isTouchpad(deltaY) {
    if (!deltaY) return;
    if (!deltaBuffer.length) {
        deltaBuffer = [deltaY, deltaY, deltaY];
    }
    deltaY = Math.abs(deltaY);
    deltaBuffer.push(deltaY);
    deltaBuffer.shift();
    var dpiScaledWheelDelta = deltaY > 120 && allDeltasDivisableBy(deltaY);
    return !allDeltasDivisableBy(120) && !allDeltasDivisableBy(100) && !dpiScaledWheelDelta;
}

function isDivisible(n, divisor) {
    return (Math.floor(n / divisor) == n / divisor);
}

function allDeltasDivisableBy(divisor) {
    return (isDivisible(deltaBuffer[0], divisor) &&
            isDivisible(deltaBuffer[1], divisor) &&
            isDivisible(deltaBuffer[2], divisor));
}

function isInsideYoutubeVideo(event) {
    var elem = event.target;
    var isControl = false;
    if (document.URL.indexOf ('www.youtube.com/watch') != -1) {
        do {
            isControl = (elem.classList &&
                         elem.classList.contains('html5-video-controls'));
            if (isControl) break;
        } while ((elem = elem.parentNode));
    }
    return isControl;
}

function getScrollRoot() {
    return document.scrollingElement || document.body;
}

/***********************************************
 * PULSE (by Michael Herf)
 ***********************************************/

function pulse_(x) {
    var val, start, expx;
    x = x * options.pulseScale;
    if (x < 1) {
        val = x - (1 - Math.exp(-x));
    } else {
        start = Math.exp(-1);
        x -= 1;
        expx = 1 - Math.exp(-x);
        val = start + (expx * (1 - start));
    }
    return val * options.pulseNormalize;
}

function pulse(x) {
    if (x >= 1) return 1;
    if (x <= 0) return 0;
    if (options.pulseNormalize == 1) {
        options.pulseNormalize /= pulse_(1);
    }
    return pulse_(x);
}

// new standard wheel event from Chrome 31+
var wheelEvent = 'onwheel' in document.createElement('div') ? 'wheel' : 'mousewheel';

addEvent(wheelEvent, wheel);
addEvent('mousedown', mousedown);
addEvent('keydown', keydown);
addEvent('load', loaded);


/***********************************************
 * PUBLIC API
 ***********************************************/

window.SmoothScroll = function (userOptions) {
    if (userOptions) {
        for (var key in userOptions) {
            if (defaultOptions.hasOwnProperty(key)) {
                options[key] = userOptions[key];
            }
        }
    }
    initTest();
    if (document.readyState === 'loading') {
        addEvent('load', loaded);
    } else {
        loaded();
    }
};
